mapper.insert:

	SELECT
		'PROJECT_'
		|| TO_CHAR(SYSDATE, 'YYMM')
		|| '_'
		|| LPAD(
			NVL(MAX(TO_NUMBER(SUBSTR(project_id, -4))), 0) + 1,
			4,
			'0'
		)
	FROM project
	WHERE SUBSTR(project_id, 1, 13) = 'PROJECT_' || TO_CHAR(SYSDATE, 'YYMM') || '_'

INSERT INTO project (
	project_id
	, owner_id
	, project_name
	, identifier
	, description
	, project_url
	, status_code
	, start_date
	, end_date
	, created_at
	, git_url
	)
VALUES (
	#{projectId}
	, #{ownerId}
	, #{projectName}
	, #{identifier}
	, #{description}
	, #{projectUrl}
	, 'a002'
	, #{startDate}
	, #{endDate}
	, SYSDATE
	, #{gitUrl}
)

